/* eslint-disable @next/next/no-img-element */
"use client";

import { useState, useRef, useLayoutEffect, useEffect } from "react";
import {
  Layout,
  Typography,
  Input,
  Button,
  Slider,
  Radio,
  Space,
  ConfigProvider,
  theme,
  Card,
  Flex,
  Modal,
} from "antd";
import { UpOutlined, DownOutlined } from "@ant-design/icons";

const { Header, Content, Footer } = Layout;
const { Title, Paragraph, Text, Link } = Typography;

type WordObject = {
  word: string;
  translation: string;
};

type LanguageFrom = "auto" | "es" | "en" | "bg";
type Language = "en" | "uk";

async function translateWord(
  word: string,
  languageFrom: LanguageFrom,
  language: Language
): Promise<string> {
  if (!word.trim()) return "";

  const params = new URLSearchParams({
    client: "gtx",
    sl: languageFrom,
    tl: language,
    dt: "t",
    q: word,
  });

  try {
    const res = await fetch(
      `https://translate.googleapis.com/translate_a/single?${params.toString()}`
    );
    const data = await res.json();
    const first = data?.[0]?.[0]?.[0];
    return typeof first === "string" ? first : "";
  } catch {
    return "";
  }
}

function tokenize(text: string): string[] {
  if (!text.trim()) return [];
  return text
    .split(/(\s+|[.,!?;:"()«»—–-])/u)
    .filter((t) => t !== "" && !/^\s+$/u.test(t));
}

function WordPair({
  item,
  textSize,
  opacity,
  isKnown,
  onToggleKnown,
}: {
  item: WordObject;
  textSize: number;
  opacity: number;
  isKnown: boolean;
  onToggleKnown: (word: string) => void;
}) {
  const pairRef = useRef<HTMLDivElement>(null);
  const originalRef = useRef<HTMLSpanElement>(null);
  const [maskStyle, setMaskStyle] = useState<React.CSSProperties>({});

  useLayoutEffect(() => {
    if (!item.translation || !pairRef.current || !originalRef.current) return;
    const pairWidth = pairRef.current.offsetWidth;
    const originalWidth = originalRef.current.offsetWidth;
    if (pairWidth <= 0 || originalWidth <= 0) return;
    const right = Math.min(100, (originalWidth / pairWidth) * 100);
    setMaskStyle({
      maskImage: `linear-gradient(to right, rgba(0,0,0,0.99) 0%, rgba(0,0,0,0.99) ${right}%, transparent ${right}%, transparent 100%)`,
      WebkitMaskImage: `linear-gradient(to right, rgba(0,0,0,0.99) 0%, rgba(0,0,0,0.99) ${right}%, transparent ${right}%, transparent 100%)`,
    });
  }, [item.word, item.translation, textSize]);

  const handleClick = () => {
    if (!item.translation) return;
    onToggleKnown(item.word);
  };

  return (
    <div
      ref={pairRef}
      className="word-pair"
      style={{ fontSize: textSize }}
    >
      {item.translation && !isKnown && (
        <span
          className="translation-with-mask"
          style={{
            fontSize: textSize * 0.55,
            opacity,
            lineHeight: 1.1,
            ...maskStyle,
          }}
        >
          {item.translation}
        </span>
      )}
      <span
        ref={originalRef}
        style={{
          lineHeight: 1.2,
          cursor: item.translation ? "pointer" : "default",
        }}
        onClick={handleClick}
      >
        {item.word}
      </span>
    </div>
  );
}

export default function Home() {
  const [inputText, setInputText] = useState<string>("");
  const [wordObjects, setWordObjects] = useState<WordObject[]>([]);
  const [textSize, setTextSize] = useState<number>(24);
  const [translationOpacity, setTranslationOpacity] = useState<number>(18);
  const [language, setLanguage] = useState<Language>("uk");
  const [languageFrom, setLanguageFrom] = useState<LanguageFrom>("auto");
  const [loading, setLoading] = useState(false);
  const [settingsCollapsed, setSettingsCollapsed] = useState(false);
  const [knownWords, setKnownWords] = useState<string[]>([]);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const raw = window.localStorage.getItem("hint-reader-state");
      if (!raw) return;
      const parsed = JSON.parse(raw);

      if (typeof parsed.inputText === "string") {
        setInputText(parsed.inputText);
      }
      if (Array.isArray(parsed.knownWords)) {
        setKnownWords(
          parsed.knownWords.filter((w: unknown) => typeof w === "string")
        );
      }
      if (typeof parsed.textSize === "number") {
        setTextSize(parsed.textSize);
      }
      if (typeof parsed.translationOpacity === "number") {
        setTranslationOpacity(parsed.translationOpacity);
      }
      if (parsed.language === "en" || parsed.language === "uk") {
        setLanguage(parsed.language);
      }
      if (
        parsed.languageFrom === "auto" ||
        parsed.languageFrom === "es" ||
        parsed.languageFrom === "en" ||
        parsed.languageFrom === "bg"
      ) {
        setLanguageFrom(parsed.languageFrom);
      }
      if (typeof parsed.settingsCollapsed === "boolean") {
        setSettingsCollapsed(parsed.settingsCollapsed);
      }
    } catch {
      // ignore malformed localStorage
    }
  }, []);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const data = {
        inputText,
        knownWords,
        textSize,
        translationOpacity,
        language,
        languageFrom,
        settingsCollapsed,
      };
      window.localStorage.setItem("hint-reader-state", JSON.stringify(data));
    } catch {
      // ignore write errors
    }
  }, [
    inputText,
    knownWords,
    textSize,
    translationOpacity,
    language,
    languageFrom,
    settingsCollapsed,
  ]);

  const toggleKnownWord = (word: string) => {
    setKnownWords((prev) =>
      prev.includes(word) ? prev.filter((w) => w !== word) : [...prev, word]
    );
  };

  const removeKnownWord = (word: string) => {
    setKnownWords((prev) => prev.filter((w) => w !== word));
  };

  const handleProcess = async () => {
    const tokens = tokenize(inputText);
    if (tokens.length === 0) {
      setWordObjects([]);
      return;
    }

    setLoading(true);
    try {
      const results: WordObject[] = [];
      for (const token of tokens) {
        if (/^\s+$/u.test(token)) {
          continue;
        }
        if (/^[.,!?;:"()«»—–-]$/u.test(token)) {
          results.push({ word: token, translation: "" });
          continue;
        }
        const translation = await translateWord(token, languageFrom, language);
        results.push({ word: token, translation });
      }
      setWordObjects(results);
    } finally {
      setLoading(false);
    }
  };

  const opacity = Math.max(1, Math.min(30, translationOpacity)) / 100;

  return (
    <ConfigProvider
      theme={{
        algorithm: theme.defaultAlgorithm,
        token: {
          colorPrimary: "#1677ff",
          borderRadius: 8,
        },
      }}
    >
      <Layout className="app-layout">
        <Header
          style={{
            background: "#ffffff",
            borderBottom: "1px solid #f0f0f0",
          }}
        >
          <Flex
            align="center"
            justify="space-between"
            style={{ maxWidth: 1120, margin: "0 auto" }}
          >
            <Title level={3} style={{ margin: 0 }}>
              Hint reader
            </Title>
            <Text type="secondary">
              Читання іноземних текстів з підказками-перекладом
            </Text>
          </Flex>
        </Header>
        <Content style={{ padding: "24px 16px 32px" }}>
          <div style={{ maxWidth: 1120, margin: "0 auto" }}>
            {!settingsCollapsed && (
              <Card
                style={{ marginBottom: 0 }}
                title="Текст та налаштування"
                headStyle={{ fontWeight: 600 }}
              >
                <Space direction="vertical" size="large" style={{ width: "100%" }}>
                  <div>
                    <Paragraph style={{ marginBottom: 8 }}>
                      Вставте або введіть текст іноземною мовою. Кожне слово буде
                      показано разом з перекладом над ним.
                    </Paragraph>
                    <Input.TextArea
                      value={inputText}
                      onChange={(e) => setInputText(e.target.value)}
                      rows={6}
                      placeholder="Наприклад: Once upon a time in a small village..."
                    />
                  </div>

                <Flex gap={24} wrap>
                    <Card
                      size="small"
                      title="Мови"
                      style={{ flex: 1, minWidth: 260 }}
                    >
                      <Space direction="vertical" size="middle" style={{ width: "100%" }}>
                        <div>
                          <Text strong>Мова оригіналу</Text>
                          <Radio.Group
                            style={{ marginTop: 8 }}
                            value={languageFrom}
                            onChange={(e) =>
                              setLanguageFrom(e.target.value as LanguageFrom)
                            }
                          >
                            <Radio.Button value="auto">Автовизначення</Radio.Button>
                            <Radio.Button value="en">English</Radio.Button>
                            <Radio.Button value="es">Español</Radio.Button>
                            <Radio.Button value="bg">Болгарська</Radio.Button>
                          </Radio.Group>
                        </div>

                        <div>
                          <Text strong>Мова перекладу</Text>
                          <Radio.Group
                            style={{ marginTop: 8 }}
                            value={language}
                            onChange={(e) => setLanguage(e.target.value as Language)}
                          >
                            <Radio.Button value="en">English</Radio.Button>
                            <Radio.Button value="uk">Українська</Radio.Button>
                          </Radio.Group>
                        </div>
                      </Space>
                    </Card>

                    <Card
                      size="small"
                      title="Вигляд тексту"
                      style={{ flex: 1, minWidth: 260 }}
                    >
                      <Space direction="vertical" size="large" style={{ width: "100%" }}>
                        <div>
                          <Text strong>Розмір тексту</Text>
                          <Slider
                            style={{ marginTop: 8 }}
                            min={15}
                            max={50}
                            value={textSize}
                            onChange={(value) => setTextSize(value as number)}
                          />
                        </div>
                        <div>
                          <Text strong>Прозорість перекладу</Text>
                          <Slider
                            style={{ marginTop: 8 }}
                            min={1}
                            max={30}
                            value={translationOpacity}
                            onChange={(value) =>
                              setTranslationOpacity(value as number)
                            }
                          />
                        </div>
                      </Space>
                    </Card>
                  </Flex>

                  <div>
                    <Space>
                      <Button
                        type="primary"
                        size="large"
                        onClick={handleProcess}
                        loading={loading}
                      >
                        Обробити текст
                      </Button>
                      <Button
                        type="default"
                        size="large"
                        onClick={() => setIsSettingsOpen(true)}
                      >
                        Known words
                      </Button>
                    </Space>
                  </div>
                </Space>
              </Card>
            )}

            <div className="settings-reading-separator">
              <div className="settings-reading-separator-line" />
              <Button
                type="text"
                icon={settingsCollapsed ? <DownOutlined /> : <UpOutlined />}
                onClick={() => setSettingsCollapsed((c) => !c)}
                className="settings-reading-separator-btn"
                aria-label={settingsCollapsed ? "Show settings" : "Hide settings"}
              />
              <div className="settings-reading-separator-line" />
            </div>

            <Card
              title="Зона читання"
              headStyle={{ fontWeight: 600 }}
              bodyStyle={{ paddingTop: 16 }}
            >
              {wordObjects.length === 0 ? (
                <Paragraph type="secondary">
                  Після обробки тексту тут з&apos;явиться текст з
                  перекладами-«підказками» над кожним словом.
                </Paragraph>
              ) : (
                <div className="reading-area">
                  {wordObjects.map((item, index) => (
                    <WordPair
                      key={`${item.word}-${index}`}
                      item={item}
                      textSize={textSize}
                      opacity={opacity}
                      isKnown={knownWords.includes(item.word)}
                      onToggleKnown={toggleKnownWord}
                    />
                  ))}
                </div>
              )}
            </Card>

            <Modal
              title="Known words"
              open={isSettingsOpen}
              onCancel={() => setIsSettingsOpen(false)}
              footer={null}
            >
              {knownWords.length === 0 ? (
                <Paragraph type="secondary">
                  You don&apos;t have any known words yet. Click a word in the
                  reading area to add it.
                </Paragraph>
              ) : (
                <Space size={[8, 8]} wrap>
                  {knownWords.map((word) => (
                    <Button
                      key={word}
                      size="small"
                      onClick={() => removeKnownWord(word)}
                    >
                      {word}
                    </Button>
                  ))}
                </Space>
              )}
            </Modal>

            <div style={{ marginTop: 16 }}>
              <Text type="secondary">
                Переклад виконується через неофіційний HTTP-інтерфейс Google
                Translate. Довгі тексти можуть оброблятися повільно та підлягати
                обмеженням за кількістю запитів.
              </Text>
            </div>
          </div>
        </Content>
        <Footer style={{ textAlign: "center" }}>
          <Text type="secondary">
            Hint reader · Створено на базі Next.js та Ant Design
          </Text>{" "}
          ·{" "}
          <Link
            href="https://nextjs.org/"
            target="_blank"
            rel="noopener noreferrer"
          >
            Next.js
          </Link>
        </Footer>
      </Layout>
    </ConfigProvider>
  );
}
